package com.chaobo.scm.supplier.infrastructure.persistence.qualification;
import com.chaobo.scm.common.api.PageResult;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.qualification.*;import com.chaobo.scm.supplier.domain.qualification.*;import org.springframework.stereotype.Repository;import java.util.*;
@Repository public class MyBatisSupplierQualificationAdapter implements SupplierQualificationRepository,SupplierQualificationReadModelPort,SupplierQualificationPolicyPort{private final SupplierQualificationMapper mapper;public MyBatisSupplierQualificationAdapter(SupplierQualificationMapper mapper){this.mapper=mapper;}public Optional<SupplierQualificationAggregate> findById(long id){var row=mapper.find(id);return row==null?Optional.empty():Optional.of(aggregate(row));}public void save(SupplierQualificationAggregate aggregate,long operator){var row=row(aggregate);if(mapper.find(aggregate.id())==null)mapper.insert(row,operator);else if(mapper.update(row,aggregate.version()-1,operator)!=1)throw new BusinessException(ErrorCode.VERSION_CONFLICT,"资质已被更新");}public boolean hasValidQualification(long supplierId){return mapper.hasValid(supplierId);}public void assertEligible(long supplierId,Long categoryId){var types=mapper.requiredTypes(categoryId);if(types.isEmpty()){if(!mapper.hasValid(supplierId))throw new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,"供应商不存在有效资质");return;}long actual=mapper.validRequiredCount(supplierId,types);if(actual!=types.stream().distinct().count())throw new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,"供应商缺少品类必需资质: "+String.join(",",types));}public Optional<SupplierQualificationView> detail(long id){var row=mapper.find(id);return row==null?Optional.empty():Optional.of(view(row));}public PageResult<SupplierQualificationView> page(Long supplierId,Integer status,int page,int size){return new PageResult<>(page,size,mapper.count(supplierId,status),mapper.page(supplierId,status,(page-1)*size,size).stream().map(this::view).toList());}public List<Long> expiredIds(){return mapper.expiredIds();}private SupplierQualificationAggregate aggregate(SupplierQualificationMapper.Row row){return SupplierQualificationAggregate.rehydrate(row.id(),row.supplierId(),row.type(),row.number(),row.from(),row.to(),row.attachment(),row.status(),row.remark(),row.version());}private SupplierQualificationMapper.Row row(SupplierQualificationAggregate aggregate){return new SupplierQualificationMapper.Row(aggregate.id(),aggregate.supplierId(),aggregate.type(),aggregate.number(),aggregate.from(),aggregate.to(),aggregate.attachment(),aggregate.status().code(),aggregate.remark(),aggregate.version());}private SupplierQualificationView view(SupplierQualificationMapper.Row row){var status=QualificationStatus.fromCode(row.status());return new SupplierQualificationView(row.id(),row.supplierId(),row.type(),row.number(),row.from(),row.to(),row.attachment(),status.code(),status.label(),row.remark(),row.version());}}
